"use client"

import { useState } from 'react'
import { HttpTypes } from '@medusajs/types'
import Link from 'next/link'
import { cn } from '@/lib/utils'
import { VerificationStatus } from './VerificationStatus'
import { SellerTrustLevel } from '@/components/common/TrustBadge'
import { invalidateCustomerProfileCache } from '@/lib/data/customer'

interface CustomerToSellerUpgradeProps {
  customer: HttpTypes.StoreCustomer
  onUpgradeComplete?: () => void
}

interface UpgradeStep {
  id: string
  title: string
  description: string
  status: 'pending' | 'in_progress' | 'completed'
  required: boolean
  icon: string
}

export function CustomerToSellerUpgrade({ customer, onUpgradeComplete }: CustomerToSellerUpgradeProps) {
  const [isUpgrading, setIsUpgrading] = useState(false)
  const [isSavingProfile, setIsSavingProfile] = useState(false)
  const [currentStep, setCurrentStep] = useState(1)
  const [agreedToTerms, setAgreedToTerms] = useState(false)
  const [sellerType, setSellerType] = useState<'consumer' | 'business'>('consumer')
  const [upgradeComplete, setUpgradeComplete] = useState(false)
  const [upgradeError, setUpgradeError] = useState<string | null>(null)

  // Step 1: Profile info
  const [displayName, setDisplayName] = useState(
    customer.first_name ? `${customer.first_name} ${customer.last_name || ''}`.trim() : ''
  )
  const [bio, setBio] = useState('')
  const [location, setLocation] = useState('')
  const [avatarFile, setAvatarFile] = useState<File | null>(null)
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null)
  const [profileError, setProfileError] = useState<string | null>(null)
  const [avatarWarning, setAvatarWarning] = useState<string | null>(null)

  // Step 3: Preferences
  const [selectedGames, setSelectedGames] = useState<string[]>([])
  const [notifyOrderUpdates, setNotifyOrderUpdates] = useState(true)
  const [notifyPriceAlerts, setNotifyPriceAlerts] = useState(true)
  const [notifyMessages, setNotifyMessages] = useState(true)
  const [profilePublic, setProfilePublic] = useState(true)
  const [showSalesHistory, setShowSalesHistory] = useState(false)
  const [isSavingPrefs, setIsSavingPrefs] = useState(false)
  const [prefsError, setPrefsError] = useState<string | null>(null)

  const TCG_GAMES = [
    { code: 'MTG', label: 'Magic: The Gathering', icon: '🧙' },
    { code: 'POKEMON', label: 'Pokémon', icon: '⚡' },
    { code: 'YUGIOH', label: 'Yu-Gi-Oh!', icon: '👁' },
    { code: 'OPTCG', label: 'One Piece', icon: '⚓' },
  ]

  const toggleGame = (code: string) => {
    setSelectedGames(prev =>
      prev.includes(code) ? prev.filter(g => g !== code) : [...prev, code]
    )
  }

  // Mock trust level for new seller
  const newSellerTrustLevel: SellerTrustLevel = {
    level: 'unverified',
    score: 60,
    reviewCount: 0,
    isBusinessSeller: sellerType === 'business',
    hasIdVerification: false,
    hasAddressVerification: false,
    hasPaymentVerification: false,
    accountAge: 1, // Will use existing customer account age
    totalSales: 0
  }

  const upgradeSteps: UpgradeStep[] = [
    {
      id: 'profile',
      title: 'Your Profile',
      description: 'Set up your public profile information',
      status: currentStep > 1 ? 'completed' : currentStep === 1 ? 'in_progress' : 'pending',
      required: true,
      icon: '🪪'
    },
    {
      id: 'seller_type',
      title: 'Seller Type',
      description: 'Select whether you want to sell as an individual or business',
      status: currentStep > 2 ? 'completed' : currentStep === 2 ? 'in_progress' : 'pending',
      required: true,
      icon: '👤'
    },
    {
      id: 'preferences',
      title: 'Preferences',
      description: 'Choose your TCG interests and notification settings',
      status: currentStep > 3 ? 'completed' : currentStep === 3 ? 'in_progress' : 'pending',
      required: false,
      icon: '🎯'
    },
    {
      id: 'terms',
      title: 'Accept Terms',
      description: 'Review and accept our seller terms and conditions',
      status: currentStep > 4 ? 'completed' : currentStep === 4 ? 'in_progress' : 'pending',
      required: true,
      icon: '📋'
    },
    {
      id: 'verification',
      title: 'Activate',
      description: 'Complete basic seller verification steps',
      status: currentStep > 5 ? 'completed' : currentStep === 5 ? 'in_progress' : 'pending',
      required: false,
      icon: '✅'
    }
  ]

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0] ?? null
    setAvatarFile(file)
    if (file) {
      setAvatarPreview(prev => {
        if (prev) URL.revokeObjectURL(prev)
        return URL.createObjectURL(file)
      })
    } else {
      setAvatarPreview(prev => {
        if (prev) URL.revokeObjectURL(prev)
        return null
      })
    }
  }

  const handleProfileSave = async () => {
    if (!displayName.trim()) {
      setProfileError('Display name is required')
      return
    }
    setProfileError(null)
    setAvatarWarning(null)
    setIsSavingProfile(true)
    try {
      // Upload avatar if selected (non-blocking — profile saves even if avatar fails)
      if (avatarFile) {
        try {
          const formData = new FormData()
          formData.append('avatar', avatarFile)
          const avatarRes = await fetch(
            `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/customers/${customer.id}/profile/avatar`,
            { method: 'POST', body: formData }
          )
          if (!avatarRes.ok) {
            const err = await avatarRes.json().catch(() => ({}))
            setAvatarWarning(err.message || 'Failed to upload avatar. You can update it later from your profile.')
          }
        } catch {
          setAvatarWarning('Could not connect to upload service. You can update your avatar later.')
        }
      }

      // Save profile text fields
      const res = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/customers/${customer.id}/profile`,
        {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            display_name: displayName.trim(),
            bio: bio.trim() || undefined,
            location: location.trim() || undefined
          })
        }
      )
      if (!res.ok) {
        const err = await res.json()
        setProfileError(err.message || 'Failed to save profile')
        return
      }
      setCurrentStep(2)
    } catch {
      setProfileError('Failed to save profile. Please try again.')
    } finally {
      setIsSavingProfile(false)
    }
  }

  const handlePreferencesSave = async () => {
    setPrefsError(null)
    setIsSavingPrefs(true)
    try {
      const res = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/customers/${customer.id}/preferences`,
        {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            tcg_games: selectedGames,
            notify_order_updates: notifyOrderUpdates,
            notify_price_alerts: notifyPriceAlerts,
            notify_messages: notifyMessages,
            profile_public: profilePublic,
            show_sales_history: showSalesHistory
          })
        }
      )
      if (!res.ok) {
        const err = await res.json()
        setPrefsError(err.message || 'Failed to save preferences')
        return
      }
      setCurrentStep(4)
    } catch {
      setPrefsError('Failed to save preferences. Please try again.')
    } finally {
      setIsSavingPrefs(false)
    }
  }

  const handleUpgrade = async () => {
    setUpgradeError(null)
    setIsUpgrading(true)

    try {
      const timestamp = new Date().toISOString()

      // Register in both backends via server-side proxy
      // (proxy reads the httpOnly _medusa_jwt cookie and forwards auth headers to both backends)
      const customerResponse = await fetch('/api/customer/upgrade-to-seller', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          customer_id: customer.id,
          seller_type: sellerType,
          display_name: displayName,
          agreed_to_terms: agreedToTerms,
          timestamp,
        }),
      })

      if (!customerResponse.ok) {
        let errorMessage = 'Failed to upgrade to seller account. Please try again.'
        try {
          const error = await customerResponse.json()
          if (error && typeof error === 'object' && 'message' in error && typeof (error as { message?: unknown }).message === 'string') {
            errorMessage = (error as { message: string }).message
          }
        } catch {
          // Ignore JSON parse errors — use default message
        }
        setUpgradeError(errorMessage)
        return
      }

      await invalidateCustomerProfileCache()
      setUpgradeComplete(true)
      setCurrentStep(6)
      onUpgradeComplete?.()
    } catch (err) {
      console.error('Error upgrading to seller:', err)
      setUpgradeError('Failed to upgrade to seller account. Please try again.')
    } finally {
      setIsUpgrading(false)
    }
  }

  const getStepIcon = (status: string, icon: string) => {
    switch (status) {
      case 'completed':
        return (
          <div className="w-8 h-8 bg-green-500 rounded-full flex items-center justify-center">
            <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
            </svg>
          </div>
        )
      case 'in_progress':
        return (
          <div className="w-8 h-8 bg-blue-500 rounded-full flex items-center justify-center">
            <div className="w-3 h-3 bg-white rounded-full animate-pulse" />
          </div>
        )
      default:
        return (
          <div className="w-8 h-8 bg-gray-300 rounded-full flex items-center justify-center">
            <span className="text-sm">{icon}</span>
          </div>
        )
    }
  }

  if (upgradeComplete) {
    return (
      <div className="max-w-4xl mx-auto p-6">
        {/* Success State */}
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <svg className="w-8 h-8 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
            </svg>
          </div>
          <h1 className="text-3xl font-bold text-primary mb-2">
            🎉 Welcome to SideDecked Selling!
          </h1>
          <p className="text-lg text-secondary">
            Your seller account has been activated successfully
          </p>
        </div>

        {/* Next Steps */}
        <div className="bg-card rounded-lg border border-border p-6 mb-6">
          <h3 className="text-lg font-semibold text-primary mb-4">What&apos;s Next?</h3>
          <div className="grid md:grid-cols-2 gap-4">
            <Link
              href="/sell/list-card"
              className="flex items-center gap-3 p-4 bg-component rounded-lg hover:bg-component-hover transition-colors"
            >
              <div className="w-10 h-10 bg-green-100 dark:bg-green-900/20 rounded-lg flex items-center justify-center">
                <svg className="w-5 h-5 text-green-600 dark:text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
              </div>
              <div>
                <h4 className="font-medium text-primary">List Your First Card</h4>
                <p className="text-sm text-secondary">Start selling cards from your collection</p>
              </div>
            </Link>

            <Link
              href="/user/settings"
              className="flex items-center gap-3 p-4 bg-component rounded-lg hover:bg-component-hover transition-colors"
            >
              <div className="w-10 h-10 bg-blue-100 dark:bg-blue-900/20 rounded-lg flex items-center justify-center">
                <svg className="w-5 h-5 text-blue-600 dark:text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                </svg>
              </div>
              <div>
                <h4 className="font-medium text-primary">Complete Verification</h4>
                <p className="text-sm text-secondary">Improve trust score and unlock features</p>
              </div>
            </Link>
          </div>
        </div>

        {/* Verification Status */}
        <VerificationStatus trustLevel={newSellerTrustLevel} customer={customer} />
      </div>
    )
  }

  return (
    <div className="max-w-4xl mx-auto p-6">
      {/* Header */}
      <div className="text-center mb-8">
        <h1 className="text-3xl font-bold text-primary mb-2">
          Become a SideDecked Seller
        </h1>
        <p className="text-lg text-secondary">
          Transform your card collection into income. Start selling today!
        </p>
      </div>

      {/* Progress Steps */}
      <div className="mb-8">
        <div className="flex items-center justify-between mb-4">
          {upgradeSteps.map((step, index) => (
            <div key={step.id} className="flex items-center">
              <div className="flex flex-col items-center">
                {getStepIcon(step.status, step.icon)}
                <span className={cn(
                  "text-xs mt-2 text-center max-w-20",
                  step.status === 'completed' ? 'text-green-600' :
                  step.status === 'in_progress' ? 'text-blue-600' : 'text-gray-400'
                )}>
                  {step.title}
                </span>
              </div>
              {index < upgradeSteps.length - 1 && (
                <div className={cn(
                  "w-12 h-0.5 mx-4 mb-6",
                  upgradeSteps[index + 1].status === 'completed' || upgradeSteps[index + 1].status === 'in_progress'
                    ? 'bg-blue-500' : 'bg-gray-300'
                )} />
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Step Content */}
      <div className="bg-card rounded-lg border border-border p-6 mb-6">
        {currentStep === 1 && (
          <div>
            <h3 className="text-xl font-semibold text-primary mb-4">Your Profile</h3>
            <p className="text-secondary mb-6">
              This is how buyers will see you on SideDecked. You can update this any time from your profile settings.
            </p>

            {/* Avatar */}
            <div className="flex items-center gap-4 mb-6">
              <div className="w-20 h-20 rounded-full bg-component flex items-center justify-center overflow-hidden border border-border shrink-0">
                {avatarPreview ? (
                  // eslint-disable-next-line @next/next/no-img-element
                  <img src={avatarPreview} alt="Avatar preview" className="w-full h-full object-cover" />
                ) : (
                  <svg className="w-8 h-8 text-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                  </svg>
                )}
              </div>
              <div>
                <label
                  htmlFor="avatar-upload"
                  className="cursor-pointer text-sm text-action hover:underline"
                >
                  {avatarPreview ? 'Change photo' : 'Upload a photo'} (optional)
                </label>
                <p className="text-xs text-secondary mt-0.5">JPG, PNG or GIF · max 5 MB</p>
                <input
                  id="avatar-upload"
                  type="file"
                  accept="image/*"
                  className="sr-only"
                  onChange={handleAvatarChange}
                />
              </div>
            </div>

            {/* Display name */}
            <div className="mb-4">
              <label className="block text-sm font-medium text-primary mb-1">
                Display name <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={displayName}
                onChange={(e) => setDisplayName(e.target.value)}
                maxLength={100}
                placeholder="e.g. CardShark99"
                className="w-full px-3 py-2 bg-component border border-border rounded-lg text-primary placeholder:text-secondary focus:outline-none focus:ring-2 focus:ring-action"
              />
            </div>

            {/* Bio */}
            <div className="mb-4">
              <label className="block text-sm font-medium text-primary mb-1">
                Bio <span className="text-secondary font-normal">(optional)</span>
              </label>
              <textarea
                value={bio}
                onChange={(e) => setBio(e.target.value)}
                maxLength={2000}
                rows={3}
                placeholder="Tell buyers a little about yourself..."
                className="w-full px-3 py-2 bg-component border border-border rounded-lg text-primary placeholder:text-secondary focus:outline-none focus:ring-2 focus:ring-action resize-none"
              />
            </div>

            {/* Location */}
            <div className="mb-6">
              <label className="block text-sm font-medium text-primary mb-1">
                Location <span className="text-secondary font-normal">(optional)</span>
              </label>
              <input
                type="text"
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                maxLength={255}
                placeholder="e.g. New York, US"
                className="w-full px-3 py-2 bg-component border border-border rounded-lg text-primary placeholder:text-secondary focus:outline-none focus:ring-2 focus:ring-action"
              />
            </div>

            {profileError && (
              <p className="text-sm text-red-500 mb-4">{profileError}</p>
            )}

            {avatarWarning && (
              <p className="text-sm text-amber-600 mb-4">{avatarWarning}</p>
            )}

            <div className="flex justify-end">
              <button
                onClick={handleProfileSave}
                disabled={isSavingProfile || !displayName.trim()}
                className="px-6 py-2 bg-action text-white rounded-lg hover:bg-action-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center gap-2"
              >
                {isSavingProfile && (
                  <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                )}
                {isSavingProfile ? 'Saving...' : 'Continue'}
              </button>
            </div>
          </div>
        )}

        {currentStep === 2 && (
          <div>
            <h3 className="text-xl font-semibold text-primary mb-4">Choose Your Seller Type</h3>
            <p className="text-secondary mb-6">
              Select the type of seller account that best fits your needs
            </p>
            
            <div className="grid md:grid-cols-2 gap-4 mb-6">
              <div
                onClick={() => setSellerType('consumer')}
                className={cn(
                  "p-6 rounded-lg border cursor-pointer transition-all",
                  sellerType === 'consumer'
                    ? "border-action bg-action/5 shadow-sm"
                    : "border-border hover:border-action/50"
                )}
              >
                <div className="flex items-center mb-3">
                  <div className="w-10 h-10 bg-blue-100 dark:bg-blue-900/20 rounded-lg flex items-center justify-center mr-3">
                    <svg className="w-5 h-5 text-blue-600 dark:text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                    </svg>
                  </div>
                  <h4 className="text-lg font-semibold text-primary">Individual Seller</h4>
                  {sellerType === 'consumer' && (
                    <div className="ml-auto">
                      <div className="w-5 h-5 bg-action rounded-full flex items-center justify-center">
                        <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                        </svg>
                      </div>
                    </div>
                  )}
                </div>
                <p className="text-secondary text-sm mb-4">
                  Perfect for collectors selling cards from their personal collection
                </p>
                <ul className="text-sm text-secondary space-y-1">
                  <li className="flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full" />
                    Quick setup - start selling in minutes
                  </li>
                  <li className="flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full" />
                    Standard seller fees
                  </li>
                  <li className="flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full" />
                    Personal seller profile
                  </li>
                </ul>
              </div>

              <div
                onClick={() => setSellerType('business')}
                className={cn(
                  "p-6 rounded-lg border cursor-pointer transition-all",
                  sellerType === 'business'
                    ? "border-action bg-action/5 shadow-sm"
                    : "border-border hover:border-action/50"
                )}
              >
                <div className="flex items-center mb-3">
                  <div className="w-10 h-10 bg-purple-100 dark:bg-purple-900/20 rounded-lg flex items-center justify-center mr-3">
                    <svg className="w-5 h-5 text-purple-600 dark:text-purple-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-2M7 21h2m-2 0H3m2 0h2m-2 0v-4a2 2 0 012-2h2a2 2 0 012 2v4m-2 0V9a2 2 0 00-2-2H9a2 2 0 00-2 2v8" />
                    </svg>
                  </div>
                  <h4 className="text-lg font-semibold text-primary">Business Seller</h4>
                  {sellerType === 'business' && (
                    <div className="ml-auto">
                      <div className="w-5 h-5 bg-action rounded-full flex items-center justify-center">
                        <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                        </svg>
                      </div>
                    </div>
                  )}
                </div>
                <p className="text-secondary text-sm mb-4">
                  For card stores, dealers, and businesses selling cards professionally
                </p>
                <ul className="text-sm text-secondary space-y-1">
                  <li className="flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full" />
                    Advanced seller tools
                  </li>
                  <li className="flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full" />
                    Bulk listing capabilities
                  </li>
                  <li className="flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full" />
                    Business verification badge
                  </li>
                </ul>
              </div>
            </div>

            <div className="flex justify-between">
              <button
                onClick={() => setCurrentStep(1)}
                className="px-6 py-2 border border-border text-secondary rounded-lg hover:bg-component transition-colors"
              >
                Back
              </button>
              <button
                onClick={() => setCurrentStep(3)}
                disabled={!sellerType}
                className="px-6 py-2 bg-action text-white rounded-lg hover:bg-action-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                Continue
              </button>
            </div>
          </div>
        )}

        {currentStep === 3 && (
          <div>
            <h3 className="text-xl font-semibold text-primary mb-4">Your Preferences</h3>
            <p className="text-secondary mb-6">
              Personalize your SideDecked experience. You can change these any time in settings.
            </p>

            {/* TCG Game selection */}
            <div className="mb-6">
              <p className="text-sm font-medium text-primary mb-3">Which TCG games are you interested in?</p>
              <div className="grid grid-cols-2 gap-3">
                {TCG_GAMES.map(game => (
                  <button
                    key={game.code}
                    type="button"
                    onClick={() => toggleGame(game.code)}
                    className={cn(
                      'flex items-center gap-3 p-3 rounded-lg border text-left transition-all',
                      selectedGames.includes(game.code)
                        ? 'border-action bg-action/5'
                        : 'border-border hover:border-action/50'
                    )}
                  >
                    <span className="text-xl">{game.icon}</span>
                    <span className="text-sm font-medium text-primary">{game.label}</span>
                    {selectedGames.includes(game.code) && (
                      <div className="ml-auto w-4 h-4 bg-action rounded-full flex items-center justify-center shrink-0">
                        <svg className="w-2.5 h-2.5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                        </svg>
                      </div>
                    )}
                  </button>
                ))}
              </div>
            </div>

            {/* Notifications */}
            <div className="mb-6">
              <p className="text-sm font-medium text-primary mb-3">Notifications</p>
              <div className="space-y-3">
                {[
                  { label: 'Order updates', value: notifyOrderUpdates, setter: setNotifyOrderUpdates },
                  { label: 'Price alerts', value: notifyPriceAlerts, setter: setNotifyPriceAlerts },
                  { label: 'Messages from buyers', value: notifyMessages, setter: setNotifyMessages },
                ].map(item => (
                  <label key={item.label} className="flex items-center justify-between cursor-pointer">
                    <span className="text-sm text-primary">{item.label}</span>
                    <button
                      type="button"
                      onClick={() => item.setter(!item.value)}
                      className={cn(
                        'relative inline-flex h-5 w-9 items-center rounded-full transition-colors',
                        item.value ? 'bg-action' : 'bg-gray-300 dark:bg-gray-600'
                      )}
                    >
                      <span className={cn(
                        'inline-block h-3.5 w-3.5 rounded-full bg-white shadow transition-transform',
                        item.value ? 'translate-x-4' : 'translate-x-1'
                      )} />
                    </button>
                  </label>
                ))}
              </div>
            </div>

            {/* Privacy */}
            <div className="mb-6">
              <p className="text-sm font-medium text-primary mb-3">Privacy</p>
              <div className="space-y-3">
                {[
                  { label: 'Public profile', value: profilePublic, setter: setProfilePublic },
                  { label: 'Show sales history on profile', value: showSalesHistory, setter: setShowSalesHistory },
                ].map(item => (
                  <label key={item.label} className="flex items-center justify-between cursor-pointer">
                    <span className="text-sm text-primary">{item.label}</span>
                    <button
                      type="button"
                      onClick={() => item.setter(!item.value)}
                      className={cn(
                        'relative inline-flex h-5 w-9 items-center rounded-full transition-colors',
                        item.value ? 'bg-action' : 'bg-gray-300 dark:bg-gray-600'
                      )}
                    >
                      <span className={cn(
                        'inline-block h-3.5 w-3.5 rounded-full bg-white shadow transition-transform',
                        item.value ? 'translate-x-4' : 'translate-x-1'
                      )} />
                    </button>
                  </label>
                ))}
              </div>
            </div>

            {prefsError && (
              <p className="text-sm text-red-500 mb-4">{prefsError}</p>
            )}

            <div className="flex justify-between">
              <button
                onClick={() => setCurrentStep(2)}
                className="px-6 py-2 border border-border text-secondary rounded-lg hover:bg-component transition-colors"
              >
                Back
              </button>
              <button
                onClick={handlePreferencesSave}
                disabled={isSavingPrefs}
                className="px-6 py-2 bg-action text-white rounded-lg hover:bg-action-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center gap-2"
              >
                {isSavingPrefs && (
                  <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                )}
                {isSavingPrefs ? 'Saving...' : 'Continue'}
              </button>
            </div>
          </div>
        )}

        {currentStep === 4 && (
          <div>
            <h3 className="text-xl font-semibold text-primary mb-4">Seller Terms & Conditions</h3>
            <p className="text-secondary mb-6">
              Please review and accept our seller terms to continue
            </p>
            
            <div className="bg-component rounded-lg p-6 mb-6 max-h-64 overflow-y-auto">
              <h4 className="font-semibold text-primary mb-3">SideDecked Seller Agreement</h4>
              <div className="text-sm text-secondary space-y-3">
                <p>
                  <strong>1. Account Requirements:</strong> You must be at least 18 years old and provide accurate information.
                </p>
                <p>
                  <strong>2. Listing Standards:</strong> All cards must be accurately described with honest condition assessments.
                </p>
                <p>
                  <strong>3. Payment Terms:</strong> Payouts are processed weekly. Standard processing fees apply.
                </p>
                <p>
                  <strong>4. Shipping Requirements:</strong> Orders must be shipped within 2 business days using adequate protection.
                </p>
                <p>
                  <strong>5. Customer Service:</strong> Sellers must respond to buyer messages within 24 hours.
                </p>
                <p>
                  <strong>6. Prohibited Items:</strong> No counterfeit cards, damaged cards misrepresented as mint, or inappropriate content.
                </p>
                <p>
                  <strong>7. Dispute Resolution:</strong> SideDecked may mediate disputes and make final decisions on refunds.
                </p>
              </div>
            </div>

            <div className="flex items-center mb-6">
              <input
                type="checkbox"
                id="terms"
                checked={agreedToTerms}
                onChange={(e) => setAgreedToTerms(e.target.checked)}
                className="w-4 h-4 text-action bg-gray-100 border-gray-300 rounded focus:ring-action focus:ring-2"
              />
              <label htmlFor="terms" className="ml-3 text-sm text-secondary">
                I have read and agree to the <Link href="/terms/seller" className="text-action hover:underline">Seller Terms & Conditions</Link>
              </label>
            </div>

            <div className="flex justify-between">
              <button
                onClick={() => setCurrentStep(3)}
                className="px-6 py-2 border border-border text-secondary rounded-lg hover:bg-component transition-colors"
              >
                Back
              </button>
              <button
                onClick={() => setCurrentStep(5)}
                disabled={!agreedToTerms}
                className="px-6 py-2 bg-action text-white rounded-lg hover:bg-action-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                Accept & Continue
              </button>
            </div>
          </div>
        )}

        {currentStep === 5 && (
          <div>
            <h3 className="text-xl font-semibold text-primary mb-4">Complete Your Seller Setup</h3>
            <p className="text-secondary mb-6">
              You&apos;re almost ready! Complete the setup to activate your seller account.
            </p>
            
            <div className="bg-blue-50 dark:bg-blue-900/10 border border-blue-200 dark:border-blue-800 rounded-lg p-4 mb-6">
              <div className="flex items-start gap-3">
                <div className="w-6 h-6 bg-blue-100 dark:bg-blue-900/20 rounded-full flex items-center justify-center mt-0.5">
                  <svg className="w-4 h-4 text-blue-600 dark:text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                </div>
                <div>
                  <h4 className="font-medium text-primary mb-1">Your existing account will be preserved</h4>
                  <p className="text-sm text-secondary">
                    All your purchase history, wishlists, and account settings will remain intact. 
                    We&apos;re simply adding seller capabilities to your existing account.
                  </p>
                </div>
              </div>
            </div>

            <div className="space-y-4 mb-6">
              <div className="flex items-center justify-between py-3 px-4 bg-component rounded-lg">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 bg-green-100 dark:bg-green-900/20 rounded-lg flex items-center justify-center">
                    <svg className="w-4 h-4 text-green-600 dark:text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                    </svg>
                  </div>
                  <div>
                    <p className="font-medium text-primary">Account Type</p>
                    <p className="text-sm text-secondary capitalize">{sellerType} seller</p>
                  </div>
                </div>
                <span className="text-xs bg-green-100 text-green-700 px-2 py-1 rounded-full">Ready</span>
              </div>

              <div className="flex items-center justify-between py-3 px-4 bg-component rounded-lg">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 bg-green-100 dark:bg-green-900/20 rounded-lg flex items-center justify-center">
                    <svg className="w-4 h-4 text-green-600 dark:text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                    </svg>
                  </div>
                  <div>
                    <p className="font-medium text-primary">Email Verified</p>
                    <p className="text-sm text-secondary">{customer.email}</p>
                  </div>
                </div>
                <span className="text-xs bg-green-100 text-green-700 px-2 py-1 rounded-full">Verified</span>
              </div>

              <div className="flex items-center justify-between py-3 px-4 bg-component rounded-lg">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 bg-yellow-100 dark:bg-yellow-900/20 rounded-lg flex items-center justify-center">
                    <svg className="w-4 h-4 text-yellow-600 dark:text-yellow-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                  </div>
                  <div>
                    <p className="font-medium text-primary">Payment Setup</p>
                    <p className="text-sm text-secondary">Complete after activation</p>
                  </div>
                </div>
                <span className="text-xs bg-yellow-100 text-yellow-700 px-2 py-1 rounded-full">Optional</span>
              </div>
            </div>

            {upgradeError && (
              <div className="mb-4 p-3 bg-red-50 dark:bg-red-900/10 border border-red-200 dark:border-red-800 rounded-lg">
                <p className="text-sm text-red-600 dark:text-red-400">{upgradeError}</p>
              </div>
            )}

            <div className="flex justify-between">
              <button
                onClick={() => setCurrentStep(4)}
                className="px-6 py-2 border border-border text-secondary rounded-lg hover:bg-component transition-colors"
              >
                Back
              </button>
              <button
                onClick={handleUpgrade}
                disabled={isUpgrading}
                className="px-6 py-2 bg-action text-white rounded-lg hover:bg-action-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center gap-2"
              >
                {isUpgrading && (
                  <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                )}
                {isUpgrading ? 'Activating...' : 'Activate Seller Account'}
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Benefits Section */}
      <div className="bg-card rounded-lg border border-border p-6">
        <h3 className="text-lg font-semibold text-primary mb-4">Why Sell on SideDecked?</h3>
        <div className="grid md:grid-cols-3 gap-4">
          <div className="text-center">
            <div className="w-12 h-12 bg-green-100 dark:bg-green-900/20 rounded-lg flex items-center justify-center mx-auto mb-3">
              <svg className="w-6 h-6 text-green-600 dark:text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <h4 className="font-medium text-primary mb-2">Competitive Fees</h4>
            <p className="text-sm text-secondary">
              Low seller fees with transparent pricing. Keep more of what you earn.
            </p>
          </div>

          <div className="text-center">
            <div className="w-12 h-12 bg-blue-100 dark:bg-blue-900/20 rounded-lg flex items-center justify-center mx-auto mb-3">
              <svg className="w-6 h-6 text-blue-600 dark:text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
              </svg>
            </div>
            <h4 className="font-medium text-primary mb-2">Large Audience</h4>
            <p className="text-sm text-secondary">
              Reach thousands of card collectors and players actively looking to buy.
            </p>
          </div>

          <div className="text-center">
            <div className="w-12 h-12 bg-purple-100 dark:bg-purple-900/20 rounded-lg flex items-center justify-center mx-auto mb-3">
              <svg className="w-6 h-6 text-purple-600 dark:text-purple-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <h4 className="font-medium text-primary mb-2">Seller Protection</h4>
            <p className="text-sm text-secondary">
              Built-in fraud protection and dispute resolution to keep you safe.
            </p>
          </div>
        </div>
      </div>
    </div>
  )
}

"use client"

import { useState, useEffect } from 'react'
import { HttpTypes } from '@medusajs/types'
import Link from 'next/link'
import { cn } from '@/lib/utils'
import { customerBackendAPI } from '@/lib/api/customer-backend'
import { TrustHistoryChart } from './TrustHistoryChart'
import { ReviewManagement } from './ReviewManagement'

interface ReputationDashboardProps {
  customer: HttpTypes.StoreCustomer
  sellerId: string
}

const TIER_COLORS: Record<string, { bg: string; text: string; bar: string }> = {
  bronze: { bg: 'bg-orange-100 dark:bg-orange-900/20', text: 'text-orange-700 dark:text-orange-300', bar: 'bg-orange-500' },
  silver: { bg: 'bg-gray-100 dark:bg-gray-700/30', text: 'text-gray-700 dark:text-gray-300', bar: 'bg-gray-400' },
  gold: { bg: 'bg-yellow-100 dark:bg-yellow-900/20', text: 'text-yellow-700 dark:text-yellow-300', bar: 'bg-yellow-500' },
  platinum: { bg: 'bg-cyan-100 dark:bg-cyan-900/20', text: 'text-cyan-700 dark:text-cyan-300', bar: 'bg-cyan-500' },
  diamond: { bg: 'bg-purple-100 dark:bg-purple-900/20', text: 'text-purple-700 dark:text-purple-300', bar: 'bg-purple-500' },
}

const FACTOR_INFO: Record<string, { label: string; icon: string; max: number }> = {
  rating_score: { label: 'Rating', max: 200, icon: 'M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z' },
  volume_score: { label: 'Sales Volume', max: 150, icon: 'M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z' },
  experience_score: { label: 'Experience', max: 100, icon: 'M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z' },
  performance_score: { label: 'Performance', max: 200, icon: 'M13 10V3L4 14h7v7l9-11h-7z' },
  verification_score: { label: 'Verification', max: 150, icon: 'M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z' },
  dispute_score: { label: 'Dispute Rate', max: 100, icon: 'M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.964-.833-2.732 0L4.082 16.5c-.77.833.192 2.5 1.732 2.5z' },
  consistency_score: { label: 'Consistency', max: 100, icon: 'M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15' },
  recency_score: { label: 'Recent Activity', max: 100, icon: 'M13 7h8m0 0v8m0-8l-8 8-4-4-6 6' },
}

type ReputationData = Awaited<ReturnType<typeof customerBackendAPI.getSellerReputation>>['data']

export function ReputationDashboard({ customer, sellerId }: ReputationDashboardProps) {
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [data, setData] = useState<ReputationData | null>(null)
  const [activeSection, setActiveSection] = useState<'overview' | 'history' | 'reviews'>('overview')

  // Verification action state
  const [phoneNumber, setPhoneNumber] = useState('')
  const [verifyingPhone, setVerifyingPhone] = useState(false)
  const [verifyingId, setVerifyingId] = useState(false)
  const [verifyMessage, setVerifyMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null)

  useEffect(() => {
    loadReputation()
  }, [sellerId])

  const loadReputation = async () => {
    try {
      setLoading(true)
      setError(null)
      const response = await customerBackendAPI.getSellerReputation(sellerId)
      if (response.success) {
        setData(response.data)
      } else {
        setError('Unable to load reputation data.')
      }
    } catch {
      setError('Unable to load reputation data. Please try again.')
    } finally {
      setLoading(false)
    }
  }

  const handlePhoneVerification = async () => {
    if (!phoneNumber.trim()) return
    setVerifyingPhone(true)
    setVerifyMessage(null)
    try {
      const response = await customerBackendAPI.submitPhoneVerification(sellerId, phoneNumber)
      if (response.success) {
        setVerifyMessage({ type: 'success', text: 'Phone number verified successfully!' })
        loadReputation()
      }
    } catch {
      setVerifyMessage({ type: 'error', text: 'Phone verification failed. Please try again.' })
    } finally {
      setVerifyingPhone(false)
    }
  }

  const handleIdVerification = async (documentType: 'passport' | 'drivers_license' | 'national_id') => {
    setVerifyingId(true)
    setVerifyMessage(null)
    try {
      const response = await customerBackendAPI.submitIdVerification(sellerId, documentType)
      if (response.success) {
        setVerifyMessage({ type: 'success', text: response.data.message })
        loadReputation()
      }
    } catch {
      setVerifyMessage({ type: 'error', text: 'ID verification submission failed. Please try again.' })
    } finally {
      setVerifyingId(false)
    }
  }

  if (loading) {
    return (
      <div className="space-y-6">
        <div className="animate-pulse space-y-4">
          <div className="h-8 bg-gray-200 dark:bg-gray-700 rounded w-1/3" />
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="h-32 bg-gray-200 dark:bg-gray-700 rounded-lg" />
            ))}
          </div>
          <div className="h-64 bg-gray-200 dark:bg-gray-700 rounded-lg" />
        </div>
      </div>
    )
  }

  if (error || !data) {
    return (
      <div className="bg-card rounded-lg border border-border p-8 text-center">
        <svg className="w-12 h-12 text-red-400 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.964-.833-2.732 0L4.082 16.5c-.77.833.192 2.5 1.732 2.5z" />
        </svg>
        <p className="text-secondary mb-4">{error || 'No data available.'}</p>
        <button
          onClick={loadReputation}
          className="px-4 py-2 bg-action text-white rounded-lg hover:bg-action-hover transition-colors"
        >
          Try Again
        </button>
      </div>
    )
  }

  const tierColors = TIER_COLORS[data.seller_tier.toLowerCase()] ?? TIER_COLORS.bronze

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h2 className="text-2xl font-bold text-primary">Seller Reputation</h2>
          <p className="text-secondary">Track and improve your trust score and seller rating</p>
        </div>
        <Link
          href="/sell"
          className="mt-2 sm:mt-0 inline-flex items-center gap-2 text-sm text-action hover:text-action-hover transition-colors"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
          Back to Dashboard
        </Link>
      </div>

      {/* Trust Score Hero */}
      <div className="bg-card rounded-lg border border-border p-6">
        <div className="flex flex-col md:flex-row md:items-center gap-6">
          {/* Score Gauge */}
          <div className="flex-shrink-0 text-center">
            <div className="relative inline-flex items-center justify-center w-32 h-32">
              <svg className="w-32 h-32 transform -rotate-90" viewBox="0 0 120 120">
                <circle cx="60" cy="60" r="50" fill="none" stroke="currentColor" strokeWidth="8" className="text-gray-200 dark:text-gray-700" />
                <circle
                  cx="60"
                  cy="60"
                  r="50"
                  fill="none"
                  strokeWidth="8"
                  strokeLinecap="round"
                  className={tierColors.bar}
                  stroke="currentColor"
                  strokeDasharray={`${(data.trust_score / 1000) * 314} 314`}
                />
              </svg>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-3xl font-bold text-primary">{data.trust_score}</span>
                <span className="text-xs text-secondary">/ 1000</span>
              </div>
            </div>
            <div className="mt-2">
              <span className={cn("px-3 py-1 rounded-full text-sm font-semibold capitalize", tierColors.bg, tierColors.text)}>
                {data.seller_tier}
              </span>
            </div>
          </div>

          {/* Tier Progress + Summary */}
          <div className="flex-1 space-y-4">
            {data.tier_progress.next_tier ? (
              <div>
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm font-medium text-primary capitalize">
                    {data.tier_progress.current_tier} &rarr; {data.tier_progress.next_tier}
                  </span>
                  <span className="text-sm text-secondary">
                    {data.tier_progress.progress_percentage}%
                  </span>
                </div>
                <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-3">
                  <div
                    className={cn("h-3 rounded-full transition-all duration-500", tierColors.bar)}
                    style={{ width: `${data.tier_progress.progress_percentage}%` }}
                  />
                </div>
                <p className="text-xs text-secondary mt-1">
                  {data.tier_progress.next_tier_threshold! - data.trust_score} points to {data.tier_progress.next_tier}
                </p>
              </div>
            ) : (
              <p className="text-sm font-medium text-primary">
                You&apos;ve reached the highest tier!
              </p>
            )}

            {/* Key Performance Metrics */}
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
              <MetricPill label="Rating" value={data.performance.overall_rating > 0 ? data.performance.overall_rating.toFixed(1) : '--'} />
              <MetricPill label="Reviews" value={String(data.performance.total_reviews)} />
              <MetricPill label="Orders" value={String(data.performance.total_orders)} />
              <MetricPill label="On-time" value={`${data.performance.on_time_shipping_percentage}%`} />
            </div>
          </div>
        </div>
      </div>

      {/* Section Navigation */}
      <div className="border-b border-border">
        <nav className="flex space-x-8">
          {([
            { key: 'overview' as const, label: 'Overview' },
            { key: 'history' as const, label: 'Trust History' },
            { key: 'reviews' as const, label: 'Reviews' },
          ]).map(({ key, label }) => (
            <button
              key={key}
              onClick={() => setActiveSection(key)}
              className={cn(
                "py-2 px-1 border-b-2 font-medium text-sm whitespace-nowrap transition-colors",
                activeSection === key
                  ? "border-action text-action"
                  : "border-transparent text-secondary hover:text-primary hover:border-gray-300"
              )}
            >
              {label}
            </button>
          ))}
        </nav>
      </div>

      {/* Section Content */}
      {activeSection === 'overview' && (
        <div className="space-y-6">
          {/* Trust Factor Breakdown */}
          <div className="bg-card rounded-lg border border-border p-6">
            <h3 className="text-lg font-semibold text-primary mb-4">Trust Score Breakdown</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
              {Object.entries(data.trust_factors).map(([key, value]) => {
                const info = FACTOR_INFO[key]
                if (!info) return null
                return (
                  <FactorCard key={key} label={info.label} value={value} max={info.max} iconPath={info.icon} />
                )
              })}
            </div>
          </div>

          {/* Verification Checklist */}
          <div className="bg-card rounded-lg border border-border p-6">
            <h3 className="text-lg font-semibold text-primary mb-4">Verification Status</h3>
            {verifyMessage && (
              <div className={cn(
                "mb-4 p-3 rounded-lg text-sm",
                verifyMessage.type === 'success' ? "bg-green-50 text-green-700 dark:bg-green-900/20 dark:text-green-300" : "bg-red-50 text-red-700 dark:bg-red-900/20 dark:text-red-300"
              )}>
                {verifyMessage.text}
              </div>
            )}
            <div className="space-y-3">
              <VerificationRow label="Email" verified={data.verification.is_email_verified} />
              <VerificationRow label="Phone" verified={data.verification.is_phone_verified}>
                {!data.verification.is_phone_verified && (
                  <div className="flex items-center gap-2 mt-2">
                    <input
                      type="tel"
                      placeholder="+1 (555) 123-4567"
                      value={phoneNumber}
                      onChange={(e) => setPhoneNumber(e.target.value)}
                      className="px-3 py-1.5 text-sm border border-border rounded-md bg-background text-primary focus:outline-none focus:ring-1 focus:ring-action"
                    />
                    <button
                      onClick={handlePhoneVerification}
                      disabled={verifyingPhone || !phoneNumber.trim()}
                      className="px-3 py-1.5 text-sm bg-action text-white rounded-md hover:bg-action-hover disabled:opacity-50 transition-colors"
                    >
                      {verifyingPhone ? 'Verifying...' : 'Verify'}
                    </button>
                  </div>
                )}
              </VerificationRow>
              <VerificationRow label="Identity" verified={data.verification.is_identity_verified}>
                {!data.verification.is_identity_verified && data.verification.status !== 'pending' && (
                  <div className="flex items-center gap-2 mt-2">
                    <select
                      onChange={(e) => {
                        if (e.target.value) {
                          handleIdVerification(e.target.value as 'passport' | 'drivers_license' | 'national_id')
                        }
                      }}
                      disabled={verifyingId}
                      className="px-3 py-1.5 text-sm border border-border rounded-md bg-background text-primary focus:outline-none focus:ring-1 focus:ring-action"
                      defaultValue=""
                    >
                      <option value="" disabled>Select document type...</option>
                      <option value="passport">Passport</option>
                      <option value="drivers_license">Driver&apos;s License</option>
                      <option value="national_id">National ID</option>
                    </select>
                    {verifyingId && <span className="text-sm text-secondary">Submitting...</span>}
                  </div>
                )}
                {data.verification.status === 'pending' && !data.verification.is_identity_verified && (
                  <p className="text-xs text-yellow-600 dark:text-yellow-400 mt-1">Verification under review</p>
                )}
              </VerificationRow>
              <VerificationRow label="Business" verified={data.verification.is_business_verified} />
              <VerificationRow label="Address" verified={data.verification.is_address_verified} />
              <VerificationRow label="Payment" verified={data.verification.is_payment_verified} />
            </div>
          </div>

          {/* Performance Metrics */}
          <div className="bg-card rounded-lg border border-border p-6">
            <h3 className="text-lg font-semibold text-primary mb-4">Performance Metrics</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <PerformanceMetric
                label="Response Rate"
                value={`${data.performance.response_rate_percentage}%`}
                status={data.performance.response_rate_percentage >= 90 ? 'good' : data.performance.response_rate_percentage >= 70 ? 'warning' : 'poor'}
              />
              <PerformanceMetric
                label="On-Time Shipping"
                value={`${data.performance.on_time_shipping_percentage}%`}
                status={data.performance.on_time_shipping_percentage >= 95 ? 'good' : data.performance.on_time_shipping_percentage >= 80 ? 'warning' : 'poor'}
              />
              <PerformanceMetric
                label="Dispute Rate"
                value={`${data.performance.dispute_rate_percentage}%`}
                status={data.performance.dispute_rate_percentage < 2 ? 'good' : data.performance.dispute_rate_percentage < 5 ? 'warning' : 'poor'}
                lowerIsBetter
              />
              <PerformanceMetric
                label="Order Completion"
                value={`${data.performance.order_completion_rate}%`}
                status={data.performance.order_completion_rate >= 98 ? 'good' : data.performance.order_completion_rate >= 90 ? 'warning' : 'poor'}
              />
              <PerformanceMetric
                label="Overall Rating"
                value={data.performance.overall_rating > 0 ? data.performance.overall_rating.toFixed(2) : '--'}
                status={data.performance.overall_rating >= 4.5 ? 'good' : data.performance.overall_rating >= 3.5 ? 'warning' : 'poor'}
              />
              <PerformanceMetric
                label="Total Reviews"
                value={String(data.performance.total_reviews)}
                status={data.performance.total_reviews >= 50 ? 'good' : data.performance.total_reviews >= 10 ? 'warning' : 'poor'}
              />
            </div>
          </div>

          {/* Recommendations */}
          {data.recommendations.length > 0 && (
            <div className="bg-card rounded-lg border border-border p-6">
              <h3 className="text-lg font-semibold text-primary mb-4">Improvement Tips</h3>
              <ul className="space-y-3">
                {data.recommendations.map((rec, index) => (
                  <li key={index} className="flex items-start gap-3">
                    <div className="w-6 h-6 bg-blue-100 dark:bg-blue-900/20 rounded-full flex items-center justify-center flex-shrink-0 mt-0.5">
                      <svg className="w-4 h-4 text-blue-600 dark:text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                      </svg>
                    </div>
                    <p className="text-sm text-primary">{rec}</p>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      )}

      {activeSection === 'history' && (
        <TrustHistoryChart sellerId={sellerId} />
      )}

      {activeSection === 'reviews' && (
        <ReviewManagement reviews={data.recent_reviews} />
      )}
    </div>
  )
}

// --- Sub-components ---

function MetricPill({ label, value }: { label: string; value: string }) {
  return (
    <div className="bg-component rounded-lg px-3 py-2 text-center">
      <p className="text-xs text-secondary">{label}</p>
      <p className="text-lg font-semibold text-primary">{value}</p>
    </div>
  )
}

function FactorCard({ label, value, max, iconPath }: { label: string; value: number; max: number; iconPath: string }) {
  const percentage = max > 0 ? Math.round((value / max) * 100) : 0
  return (
    <div className="bg-component rounded-lg p-4">
      <div className="flex items-center gap-2 mb-2">
        <svg className="w-4 h-4 text-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={iconPath} />
        </svg>
        <span className="text-sm font-medium text-primary">{label}</span>
      </div>
      <div className="flex items-center gap-2">
        <div className="flex-1 bg-gray-200 dark:bg-gray-700 rounded-full h-2">
          <div
            className={cn(
              "h-2 rounded-full transition-all duration-500",
              percentage >= 70 ? "bg-green-500" : percentage >= 40 ? "bg-yellow-500" : "bg-red-500"
            )}
            style={{ width: `${Math.min(percentage, 100)}%` }}
          />
        </div>
        <span className="text-sm font-medium text-primary w-10 text-right">{percentage}%</span>
      </div>
    </div>
  )
}

function VerificationRow({ label, verified, children }: { label: string; verified: boolean; children?: React.ReactNode }) {
  return (
    <div className="flex flex-col">
      <div className="flex items-center gap-3">
        <div className={cn(
          "w-6 h-6 rounded-full flex items-center justify-center",
          verified ? "bg-green-500" : "bg-gray-300 dark:bg-gray-600"
        )}>
          {verified ? (
            <svg className="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
            </svg>
          ) : (
            <div className="w-2 h-2 bg-gray-600 dark:bg-gray-400 rounded-full" />
          )}
        </div>
        <span className="text-sm text-primary">{label}</span>
        <span className={cn(
          "text-xs font-medium",
          verified ? "text-green-600 dark:text-green-400" : "text-gray-500"
        )}>
          {verified ? 'Verified' : 'Not verified'}
        </span>
      </div>
      {children}
    </div>
  )
}

function PerformanceMetric({
  label,
  value,
  status,
  lowerIsBetter,
}: {
  label: string
  value: string
  status: 'good' | 'warning' | 'poor'
  lowerIsBetter?: boolean
}) {
  const statusColors = {
    good: 'text-green-600 dark:text-green-400',
    warning: 'text-yellow-600 dark:text-yellow-400',
    poor: 'text-red-600 dark:text-red-400',
  }

  const statusBg = {
    good: 'bg-green-100 dark:bg-green-900/20',
    warning: 'bg-yellow-100 dark:bg-yellow-900/20',
    poor: 'bg-red-100 dark:bg-red-900/20',
  }

  return (
    <div className={cn("rounded-lg p-4", statusBg[status])}>
      <p className="text-xs text-secondary mb-1">{label}</p>
      <p className={cn("text-xl font-bold", statusColors[status])}>{value}</p>
      <p className="text-xs text-secondary mt-1">
        {status === 'good' ? 'Excellent' : status === 'warning' ? 'Needs improvement' : 'Below target'}
        {lowerIsBetter && status === 'good' ? ' (low is good)' : ''}
      </p>
    </div>
  )
}

"use client"

import { useState } from 'react'
import { cn } from '@/lib/utils'

interface Review {
  id: string
  rating: number
  comment: string
  created_at: string
}

interface ReviewManagementProps {
  reviews: Review[]
}

export function ReviewManagement({ reviews }: ReviewManagementProps) {
  const [sortBy, setSortBy] = useState<'recent' | 'highest' | 'lowest'>('recent')

  const sortedReviews = [...reviews].sort((a, b) => {
    switch (sortBy) {
      case 'highest':
        return b.rating - a.rating
      case 'lowest':
        return a.rating - b.rating
      default:
        return new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
    }
  })

  // Rating distribution
  const distribution = [5, 4, 3, 2, 1].map(rating => ({
    rating,
    count: reviews.filter(r => Math.floor(r.rating) === rating).length,
    percentage: reviews.length > 0
      ? Math.round((reviews.filter(r => Math.floor(r.rating) === rating).length / reviews.length) * 100)
      : 0,
  }))

  const averageRating = reviews.length > 0
    ? reviews.reduce((sum, r) => sum + r.rating, 0) / reviews.length
    : 0

  return (
    <div className="space-y-6">
      {/* Rating Summary */}
      <div className="bg-card rounded-lg border border-border p-6">
        <div className="flex flex-col sm:flex-row gap-6">
          {/* Average Score */}
          <div className="text-center sm:text-left">
            <p className="text-4xl font-bold text-primary">
              {averageRating > 0 ? averageRating.toFixed(1) : '--'}
            </p>
            <div className="flex justify-center sm:justify-start mt-1">
              {[...Array(5)].map((_, i) => (
                <svg
                  key={i}
                  className={cn("w-5 h-5", i < Math.floor(averageRating) ? "text-yellow-400" : "text-gray-300")}
                  fill="currentColor"
                  viewBox="0 0 20 20"
                >
                  <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                </svg>
              ))}
            </div>
            <p className="text-sm text-secondary mt-1">
              {reviews.length} review{reviews.length !== 1 ? 's' : ''}
            </p>
          </div>

          {/* Distribution */}
          <div className="flex-1 space-y-2">
            {distribution.map(({ rating, count, percentage }) => (
              <div key={rating} className="flex items-center gap-2">
                <span className="text-sm text-secondary w-4">{rating}</span>
                <svg className="w-4 h-4 text-yellow-400" fill="currentColor" viewBox="0 0 20 20">
                  <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                </svg>
                <div className="flex-1 bg-gray-200 dark:bg-gray-700 rounded-full h-2">
                  <div
                    className="h-2 rounded-full bg-yellow-400 transition-all duration-300"
                    style={{ width: `${percentage}%` }}
                  />
                </div>
                <span className="text-xs text-secondary w-8 text-right">{count}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Sort Controls */}
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold text-primary">Reviews</h3>
        <div className="flex items-center gap-2">
          {([
            { key: 'recent' as const, label: 'Most Recent' },
            { key: 'highest' as const, label: 'Highest' },
            { key: 'lowest' as const, label: 'Lowest' },
          ]).map(({ key, label }) => (
            <button
              key={key}
              onClick={() => setSortBy(key)}
              className={cn(
                "px-3 py-1.5 text-sm rounded-md transition-colors",
                sortBy === key
                  ? "bg-action text-white"
                  : "bg-component text-secondary hover:text-primary hover:bg-component-hover"
              )}
            >
              {label}
            </button>
          ))}
        </div>
      </div>

      {/* Review List */}
      {sortedReviews.length === 0 ? (
        <div className="bg-card rounded-lg border border-border p-8 text-center">
          <svg className="w-10 h-10 text-gray-400 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
          </svg>
          <p className="text-secondary">No reviews yet. Encourage buyers to leave feedback!</p>
        </div>
      ) : (
        <div className="space-y-4">
          {sortedReviews.map((review) => (
            <div key={review.id} className="bg-card rounded-lg border border-border p-4">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-2">
                  {[...Array(5)].map((_, i) => (
                    <svg
                      key={i}
                      className={cn("w-4 h-4", i < review.rating ? "text-yellow-400" : "text-gray-300")}
                      fill="currentColor"
                      viewBox="0 0 20 20"
                    >
                      <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                    </svg>
                  ))}
                </div>
                <span className="text-xs text-secondary">
                  {formatRelativeTime(review.created_at)}
                </span>
              </div>
              {review.comment && (
                <p className="text-sm text-primary">{review.comment}</p>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

function formatRelativeTime(dateString: string): string {
  const date = new Date(dateString)
  const now = new Date()
  const diffMs = now.getTime() - date.getTime()
  const diffMins = Math.floor(diffMs / 60000)
  const diffHours = Math.floor(diffMs / 3600000)
  const diffDays = Math.floor(diffMs / 86400000)

  if (diffMins < 1) return 'just now'
  if (diffMins < 60) return `${diffMins}m ago`
  if (diffHours < 24) return `${diffHours}h ago`
  if (diffDays < 7) return `${diffDays}d ago`
  return date.toLocaleDateString()
}

"use client"

import { useState, useEffect } from 'react'
import { cn } from '@/lib/utils'
import { customerBackendAPI } from '@/lib/api/customer-backend'

interface TrustHistoryChartProps {
  sellerId: string
}

type HistoryEntry = {
  trust_score: number
  seller_tier: string
  factors: Record<string, number> | null
  score_change: number
  created_at: string
}

type HistorySummary = {
  current_score: number
  highest_score: number
  lowest_score: number
  trend: 'improving' | 'stable' | 'declining'
}

const TIER_COLORS: Record<string, string> = {
  bronze: 'text-orange-600 dark:text-orange-400',
  silver: 'text-gray-600 dark:text-gray-300',
  gold: 'text-yellow-600 dark:text-yellow-400',
  platinum: 'text-cyan-600 dark:text-cyan-400',
  diamond: 'text-purple-600 dark:text-purple-400',
}

export function TrustHistoryChart({ sellerId }: TrustHistoryChartProps) {
  const [loading, setLoading] = useState(true)
  const [entries, setEntries] = useState<HistoryEntry[]>([])
  const [summary, setSummary] = useState<HistorySummary | null>(null)
  const [daysBack, setDaysBack] = useState(90)

  useEffect(() => {
    loadHistory()
  }, [sellerId, daysBack])

  const loadHistory = async () => {
    try {
      setLoading(true)
      const response = await customerBackendAPI.getSellerTrustHistory(sellerId, { daysBack, limit: 50 })
      if (response.success) {
        setEntries(response.data.entries)
        setSummary(response.data.summary)
      }
    } catch {
      // Non-critical — show empty state
    } finally {
      setLoading(false)
    }
  }

  if (loading) {
    return (
      <div className="bg-card rounded-lg border border-border p-6">
        <div className="animate-pulse space-y-4">
          <div className="h-6 bg-muted rounded w-1/4" />
          <div className="h-48 bg-muted rounded" />
        </div>
      </div>
    )
  }

  const trendIcon = summary?.trend === 'improving'
    ? 'M13 7h8m0 0v8m0-8l-8 8-4-4-6 6'
    : summary?.trend === 'declining'
      ? 'M13 17h8m0 0V9m0 8l-8-8-4 4-6-6'
      : 'M5 12h14'

  const trendColor = summary?.trend === 'improving'
    ? 'text-green-600 dark:text-green-400'
    : summary?.trend === 'declining'
      ? 'text-red-600 dark:text-red-400'
      : 'text-gray-600 dark:text-gray-400'

  return (
    <div className="space-y-6">
      {/* Summary Stats */}
      {summary && (
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
          <div className="bg-card rounded-lg border border-border p-4">
            <p className="text-xs text-secondary">Current Score</p>
            <p className="text-2xl font-bold text-primary">{summary.current_score}</p>
          </div>
          <div className="bg-card rounded-lg border border-border p-4">
            <p className="text-xs text-secondary">Highest</p>
            <p className="text-2xl font-bold text-green-600 dark:text-green-400">{summary.highest_score}</p>
          </div>
          <div className="bg-card rounded-lg border border-border p-4">
            <p className="text-xs text-secondary">Lowest</p>
            <p className="text-2xl font-bold text-red-600 dark:text-red-400">{summary.lowest_score}</p>
          </div>
          <div className="bg-card rounded-lg border border-border p-4">
            <p className="text-xs text-secondary">Trend</p>
            <div className="flex items-center gap-2">
              <svg className={cn("w-5 h-5", trendColor)} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d={trendIcon} />
              </svg>
              <span className={cn("text-lg font-semibold capitalize", trendColor)}>{summary.trend}</span>
            </div>
          </div>
        </div>
      )}

      {/* Time Range Selector */}
      <div className="flex items-center gap-2">
        {[30, 60, 90, 180].map((days) => (
          <button
            key={days}
            onClick={() => setDaysBack(days)}
            className={cn(
              "px-3 py-1.5 text-sm rounded-md transition-colors",
              daysBack === days
                ? "bg-action text-white"
                : "bg-component text-secondary hover:text-primary hover:bg-component-hover"
            )}
          >
            {days}d
          </button>
        ))}
      </div>

      {/* History Timeline */}
      <div className="bg-card rounded-lg border border-border">
        <div className="p-6 border-b border-border">
          <h3 className="text-lg font-semibold text-primary">Score History</h3>
        </div>

        {entries.length === 0 ? (
          <div className="p-8 text-center">
            <svg className="w-10 h-10 text-gray-400 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
            </svg>
            <p className="text-secondary">No trust history available yet. Your score will be tracked over time.</p>
          </div>
        ) : (
          <>
            {/* Simple Bar Chart */}
            <div className="p-6">
              <div className="flex items-end gap-1 h-40">
                {entries.slice().reverse().map((entry, index) => {
                  const height = Math.max(4, (entry.trust_score / 1000) * 100)
                  const barColor = entry.score_change > 0
                    ? 'bg-green-500'
                    : entry.score_change < 0
                      ? 'bg-red-500'
                      : 'bg-gray-400'
                  return (
                    <div
                      key={index}
                      className="flex-1 flex flex-col items-center justify-end group relative"
                    >
                      <div
                        className={cn("w-full max-w-[20px] rounded-t transition-all", barColor)}
                        style={{ height: `${height}%` }}
                      />
                      {/* Tooltip on hover */}
                      <div className="absolute bottom-full mb-2 hidden group-hover:block z-10">
                        <div className="bg-bg-surface-1 text-primary text-xs rounded px-2 py-1 whitespace-nowrap border border-border shadow-lg">
                          <p>Score: {entry.trust_score}</p>
                          <p>Change: {entry.score_change >= 0 ? '+' : ''}{entry.score_change}</p>
                          <p className="capitalize">{entry.seller_tier}</p>
                        </div>
                      </div>
                    </div>
                  )
                })}
              </div>
            </div>

            {/* Timeline List */}
            <div className="divide-y divide-border">
              {entries.map((entry, index) => (
                <div key={index} className="px-6 py-3 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className={cn(
                      "w-2 h-2 rounded-full",
                      entry.score_change > 0 ? "bg-green-500" : entry.score_change < 0 ? "bg-red-500" : "bg-gray-400"
                    )} />
                    <div>
                      <span className="text-sm font-medium text-primary">Score: {entry.trust_score}</span>
                      <span className={cn(
                        "ml-2 text-xs font-medium",
                        TIER_COLORS[entry.seller_tier.toLowerCase()] ?? 'text-gray-600'
                      )}>
                        {entry.seller_tier}
                      </span>
                    </div>
                  </div>
                  <div className="flex items-center gap-4">
                    <span className={cn(
                      "text-sm font-medium",
                      entry.score_change > 0 ? "text-green-600 dark:text-green-400" : entry.score_change < 0 ? "text-red-600 dark:text-red-400" : "text-gray-500"
                    )}>
                      {entry.score_change >= 0 ? '+' : ''}{entry.score_change}
                    </span>
                    <span className="text-xs text-secondary">
                      {new Date(entry.created_at).toLocaleDateString()}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </>
        )}
      </div>
    </div>
  )
}

